    return b64decode(x)

def custom_encode(x):
    x=b64encode(x)
    return x.replace(b'=', b'~').replace(b'/', b'!').replace(b'+', b'-')

def pad(x):
    return x + bytes([16 - len(x) % 16] * (16 - len(x) % 16))

def xor_bytes(a,b):
    return bytes([x^y for x,y in zip(a,b)])

def oracle(raw):
    try:
        web=s.get(BASE+'?post='+custom_encode(raw).decode(), timeout=12)
        t=web.text
        return ('Incorrect padding' not in t and 'PaddingException' not in t), t
    except Exception:
        return False,''

def split_blocks(x,n=16):
    return [x[i:i+n] for i in range(0,len(x),n)]

def find_plain_block(prev,cur):
    inter=[0]*16
    plain=[0]*16
    crafted=bytearray(prev)
    for pos in range(15,-1,-1):
        padv=16-pos
        for i in range(pos+1,16):
            crafted[i]=inter[i]^padv
        found=[]
        def worker(start,end):
            loc=bytearray(crafted)
            for g in range(start,end):
                loc[pos]=g
                ok,_=oracle(bytes(loc)+cur)
                if ok:
                    found.append(g)
                    return
        threads=[]
        step=256//32
        for t in range(32):
            st=t*step
            en=(t+1)*step if t<31 else 256
            th=threading.Thread(target=worker,args=(st,en))
            th.start(); threads.append(th)
        for th in threads: th.join()
        if not found:
            raise Exception('byte not found at %d'%pos)
        g=found[0]
        inter[pos]=g^padv
        plain[pos]=inter[pos]^prev[pos]
        print('DEC_POS',pos,'BYTE',plain[pos], flush=True)
    return bytes(plain), bytes(inter)

def decrypt_all(ct_raw):
    blocks=split_blocks(ct_raw)
    out=b''
    inters=[]
    for i in range(1,len(blocks)):
        p,inter=find_plain_block(blocks[i-1],blocks[i])
        inters.append(inter)
        out+=p
        print('BLOCK',i,'PLAIN',p, flush=True)
    padv=out[-1]
    if 1 <= padv <= 16 and out.endswith(bytes([padv])*padv):
        out=out[:-padv]
    return out, inters, blocks

